// ─── EKIO: Preparar payload Klaviyo ───────────────────────────────
const body = $input.first().json.body ?? $input.first().json;

const email       = (body.email       || '').trim();
const nombre      = (body.nombre      || '').trim();
const ciudad      = (body.ciudad      || '').trim();
const whatsapp    = (body.whatsapp    || '').trim();
const wa_opt      = body.opt_in__promotional_whatsapp === true;
const score       = Number(body.score_total) || 0;
const perfil      = body.perfil       || '';
const perfil_slug = body.perfil_slug  || '';
const nivel       = Number(body.nivel) || 0;
const subscores   = body.subscores    || {};
const respuestas  = body.respuestas   || {};
const fecha       = body.fecha        || new Date().toISOString();

// Atributos del perfil — incluye phone_number si hay whatsapp
const profileAttributes = {
  email,
  first_name: nombre,
  location: { city: ciudad },
  properties: {
    score_total: score,
    Score_TF_EncuestaSensibilidad: score,
    perfil_ehs: perfil,
    perfil_slug: perfil_slug,
    nivel_ehs: nivel,
    whatsapp: whatsapp,
    ciudad: ciudad,
    opt_in__promotional_whatsapp: wa_opt,
    subscore_energia:        subscores.energia        || 0,
    subscore_sueno:          subscores.sueno          || 0,
    subscore_emocional:      subscores.emocional      || 0,
    subscore_piel:           subscores.piel           || 0,
    subscore_cardiovascular: subscores.cardiovascular || 0,
    subscore_digestivo:      subscores.digestivo      || 0,
    subscore_auditivo:       subscores.auditivo       || 0,
    subscore_neurologico:    subscores.neurologico    || 0,
    subscore_visual:         subscores.visual         || 0,
    subscore_facial:         subscores.facial         || 0,
    ...Object.fromEntries(
      Object.entries(respuestas).map(([k, v]) => [`resp_${k}`, v])
    )
  }
};

// Añadir phone_number al perfil cuando hay número de WhatsApp
if (whatsapp && whatsapp.length > 4) {
  profileAttributes.phone_number = whatsapp;
}

const klaviyoPayload = {
  data: {
    type: 'event',
    attributes: {
      time: fecha,
      metric: {
        data: {
          type: 'metric',
          attributes: { name: 'Diagnostico_Completado' }
        }
      },
      profile: {
        data: {
          type: 'profile',
          attributes: profileAttributes
        }
      },
      properties: {
        score_total: score,
        perfil_ehs: perfil,
        perfil_slug: perfil_slug,
        nivel_ehs: nivel,
        ciudad: ciudad
      }
    }
  }
};

const klaviyoPayloadLegacy = {
  data: {
    type: 'event',
    attributes: {
      time: fecha,
      metric: {
        data: {
          type: 'metric',
          attributes: { name: 'Formulario Cumplimentado' }
        }
      },
      profile: {
        data: {
          type: 'profile',
          attributes: {
            email,
            first_name: nombre,
            properties: {}
          }
        }
      },
      properties: {
        formName: 'Encuesta de Valoración de Sensibilidad a la Contaminación Electromagnética',
        score_total: score,
        Score_TF_EncuestaSensibilidad: score
      }
    }
  }
};

// Payload suscripción WhatsApp (solo usado cuando wa_opt=true)
const klaviyoWhatsAppSubscription = {
  data: {
    type: 'profile-subscription-bulk-create-job',
    attributes: {
      profiles: {
        data: [{
          type: 'profile',
          attributes: {
            phone_number: whatsapp,
            email: email,
            subscriptions: {
              sms: {
                marketing: {
                  consent: 'SUBSCRIBED'
                }
              }
            }
          }
        }]
      }
    },
    relationships: {
      list: {
        data: {
          type: 'list',
          id: 'S523PV'
        }
      }
    }
  }
};

return [{
  json: {
    klaviyoPayload,
    klaviyoPayloadLegacy,
    klaviyoWhatsAppSubscription,
    whatsapp_send: wa_opt && whatsapp.length > 4,
    whatsapp,
    nombre,
    email,
    score,
    perfil,
    perfil_slug,
    nivel
  }
}];
